import React, { useEffect, useState } from "react";
import "./App.css";
import AddAssignment from "./components/AddAssignment";
import AssignmentList from "./components/AssignmentList";
import Stats from "./components/Stats";

function App() {
  const [assignments, setAssignments] = useState([]);
  const [stats, setStats] = useState({});

  const fetchData = async () => {
    const a = await fetch("http://localhost:8080/assignments/user/1");
    const s = await fetch("http://localhost:8080/assignments/stats/1");
    setAssignments(await a.json());
    setStats(await s.json());
  };

  useEffect(() => {
    fetchData();
  }, []);

  const submit = async (id) => {
    await fetch(`http://localhost:8080/assignments/submit/${id}`, {
      method: "PUT",
    });
    fetchData();
  };

  return (
    <div className="app-container">
      <h1>AssignTrack - Assignment Submission Tracker</h1>

      <AddAssignment refresh={fetchData} />

      <AssignmentList assignments={assignments} submit={submit} />

      <Stats stats={stats} />
    </div>
  );
}

export default App;
